import { Link } from 'react-router-dom';

function TrainersList(props) {
    return (
        <div>
            <h2>Trainers List</h2>
            <ul>
                {props.trainers.map(trainer => (
                    <li key={trainer.trainerId}>
                        <Link to={`/trainers/${trainer.trainerId}`}>{trainer.name}</Link>
                    </li>
                ))}
            </ul>
        </div>
    );
}

export default TrainersList;
